  { id: 801, name: '日本秋田八峰能代海上风电', en: 'Akita Happo Noshiro Offshore Wind Farm', country: '日本', region: '东亚', cat: 'renewable', coord: [139.9, 40.2], cap: '375 MW', inv: 17, invText: '约 17 亿美元', status: '在建', year: 2027, updated: '2025-06', owner: 'Deep Wind Offshore (Equinor 等)', flagship: false, desc: '日本第一批商业海上风电竞标项目之一。', detail: '位于日本秋田县八峰町至能代市近岸海域，由以 Equinor 为主的联合体开发，装机 375 MW，是日本政府第一轮促进区海上风电公募项目，调整后目标 2027 年运营，秋田是日本海上风电开发最活跃地区。' },
  { id: 802, name: '江苏如东 H18 海上风电', en: 'Jiangsu Rudong H18 Offshore Wind', country: '中国', region: '中国', cat: 'renewable', coord: [121.5, 32.6], cap: '550 MW', inv: 12, invText: '约 90 亿元', status: '在建', year: 2026, updated: '2025-08', owner: '三峡能源', flagship: false, desc: '江苏如东外海 550MW 风电。', detail: '位于南通如东近海，三峡能源主导，装机 550 MW，2025 年列入江苏省重大项目推进，拟安装 8 MW 以上风机配 220 千伏海上升压站，建成后年上网约 15 亿千瓦时，助力江苏维持全国海上风电领先地位。' },
  { id: 803, name: '龙源江苏射阳 1GW 海上风电', en: 'Longyuan Sheyang 1GW Offshore Wind', country: '中国', region: '中国', cat: 'renewable', coord: [121.1, 33.7], cap: '1000 MW', inv: 22, invText: '约 160 亿元', status: '规划', year: 2027, updated: '2025-11', owner: '龙源电力 & 国家能源集团江苏', flagship: false, desc: '江苏盐城射阳 1GW 外海风电。', detail: '位于盐城射阳河口东南外海，龙源电力与国家能源集团江苏电力合资，拟装 126 台风机、装机 1000 MW，已列入江苏省 2025 年重大项目，预计 2026-2027 年建设，建成后将成全国最大单体海上风电场之一，年发电约 28 亿千瓦时。' },
  { id: 804, name: '美国日出海上风电场（纽约）', en: 'Sunrise Wind Offshore Wind Farm', country: '美国', region: '北美', cat: 'renewable', coord: [-72.1, 40.5], cap: '924 MW', inv: 42, invText: '约 42 亿美元', status: '在建', year: 2027, updated: '2026-06', owner: 'Orsted', flagship: false, desc: '纽约州最大在建海上风电，2026 年 2 月复工。', detail: '位于纽约州东部海域，Orsted 独资（2024 年收购 Eversource 50% 股份），84 台风机、装机 924 MW，2024 年夏开工，2025 年底停工令前完成约 45%，2026 年 2 月法院裁定恢复施工，预计 2027 年投运、为约 60 万户家庭供电。' }
